var prompt = 'You are a senior HR recruiter and talent acquisition specialist. Screen the following candidate(s) against the job description.

';
prompt += 'JOB TITLE: ' + $.input.jobTitle + '
';
prompt += 'JOB DESCRIPTION:
' + $.input.jobDescription + '

';
prompt += 'CANDIDATE DATA:
' + $.input.candidateData + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Score each candidate 1-100 on overall fit
';
prompt += '- Evaluate: technical skills, experience level, education, soft skills
';
prompt += '- Identify red flags and standout qualities
';
prompt += '- Provide specific interview questions tailored to each candidate
';
prompt += '- Give a clear hire/no-hire recommendation with reasoning

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "candidates": [
';
prompt += '    {
';
prompt += '      "name": "...",
';
prompt += '      "overallScore": 85,
';
prompt += '      "technicalScore": 80,
';
prompt += '      "experienceScore": 90,
';
prompt += '      "cultureFitScore": 85,
';
prompt += '      "strengths": ["strength1"],
';
prompt += '      "weaknesses": ["weakness1"],
';
prompt += '      "redFlags": ["flag1"],
';
prompt += '      "interviewQuestions": ["question1"],
';
prompt += '      "recommendation": "Strong Hire|Hire|Maybe|No Hire",
';
prompt += '      "reasoning": "Why this recommendation"
';
prompt += '    }
';
prompt += '  ],
';
prompt += '  "summary": "Overall assessment of candidate pool",
';
prompt += '  "topCandidate": "Name of strongest candidate"
';
prompt += '}';
return { prompt: prompt };

let raw = $.steps.aiScreen.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { candidates: [], summary: raw, topCandidate: '' }; }

var ai = $.steps.parseAI.output;
var candidates = ai.candidates || [];
var date = new Date().toISOString().split('T')[0];
var sheetData = candidates.map(function(c) {
  return {
    'Candidate Name': c.name || '',
    'Overall Score': c.overallScore || '',
    'Technical Score': c.technicalScore || '',
    'Experience Score': c.experienceScore || '',
    'Culture Fit Score': c.cultureFitScore || '',
    'Recommendation': c.recommendation || '',
    'Strengths': (c.strengths || []).join('; ').slice(0, 200),
    'Weaknesses': (c.weaknesses || []).join('; ').slice(0, 200),
    'Red Flags': (c.redFlags || []).join('; ').slice(0, 200),
    'Interview Questions': (c.interviewQuestions || []).join('; ').slice(0, 300),
    'Reasoning': (c.reasoning || '').slice(0, 300),
    'Job Title': $.input.jobTitle,
    'Date Screened': date
  };
});
return { sheetData: sheetData, candidateCount: candidates.length, date: date };

var ai = $.steps.parseAI.output;
var candidates = ai.candidates || [];
var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'CV Screening Results: ' + $.input.jobTitle, emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Candidates Screened:*\n' + candidates.length },
  { type: 'mrkdwn', text: '*Top Candidate:*\n' + (ai.topCandidate || 'N/A') }
] });
blocks.push({ type: 'divider' });
candidates.slice(0, 8).forEach(function(c) {
  var emoji = ':large_green_circle:';
  if (c.recommendation === 'No Hire') emoji = ':red_circle:';
  if (c.recommendation === 'Maybe') emoji = ':large_yellow_circle:';
  var text = emoji + ' *' + (c.name || 'Unknown') + '* - Score: ' + (c.overallScore || 'N/A') + '/100';
  text += '\n' + (c.recommendation || '') + ' | Tech: ' + (c.technicalScore || '') + ' | Exp: ' + (c.experienceScore || '') + ' | Culture: ' + (c.cultureFitScore || '');
  text += '\n_' + (c.reasoning || '').slice(0, 200) + '_';
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text } });
});
blocks.push({ type: 'divider' });
if (ai.summary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:* ' + ai.summary.slice(0, 1000) } });
}
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Screened with Claude AI via One CLI' }] });
var fallback = 'CV Screening: ' + candidates.length + ' candidates for ' + $.input.jobTitle;
return { blocks: blocks, fallback: fallback };
